__CALENDER_DAY_INDEX_DICT_LEFT = {date: i for i, date in enumerate(__TRADING_DAY_LIST)}
preIndex = -1
for date in __CALENDER_DAY_LIST:
    if date not in __CALENDER_DAY_INDEX_DICT_LEFT and preIndex:
        __CALENDER_DAY_INDEX_DICT_LEFT[date] = preIndex
    else:
        preIndex += 1
__CALENDER_DAY_INDEX_DICT_RIGHT = {date: i for i, date in enumerate(__TRADING_DAY_LIST)}
preIndex = 0
for date in __CALENDER_DAY_LIST:
    if date not in __CALENDER_DAY_INDEX_DICT_RIGHT and preIndex:
        __CALENDER_DAY_INDEX_DICT_RIGHT[date] = preIndex
    else:
        preIndex += 1


def getTradingDay(startDate, endDate):
    if startDate > endDate:
        return []
    elif startDate == endDate:
        index = __CALENDER_DAY_INDEX_DICT_LEFT[startDate]
        if __TRADING_DAY_LIST[index] != startDate:
            return []
        else:
            return [startDate]
    else:
        return __TRADING_DAY_LIST[__CALENDER_DAY_INDEX_DICT_RIGHT[startDate]
                                  :__CALENDER_DAY_INDEX_DICT_LEFT[endDate] + 1]


def getNDaysOff(date, NDaysOff):
    if NDaysOff > 0:
        index = __CALENDER_DAY_INDEX_DICT_RIGHT[date]
    elif NDaysOff < 0:
        index = __CALENDER_DAY_INDEX_DICT_LEFT[date]
    else:
        index = __CALENDER_DAY_INDEX_DICT_RIGHT[date]
        if __TRADING_DAY_LIST[index] != date:
            raise Exception("NDaysOff is zero when the given date is not a trading day")

    return __TRADING_DAY_LIST[index - NDaysOff]
